  ('dietitian-moex-10924', 'dietitian', 'dietitian-moex-093-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '關於營養教育的目標，下列敘述何者錯誤？ 維持學習者的態度  增加學習者的知識  提高學習者的理解  使學習者獲得技能', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "bb7efa92b0dc", "answer_pdf_sha1": "d33d11725d39", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
